    "file": "ghost/core/core/server/api/endpoints/comment-likes.js",
    "line": 8,
    "severity": "medium",
    "description": "The browse endpoint is missing cache control headers. Ghost API conventions require read-only endpoints to declare cache behavior via headers. Without this, the endpoint violates Ghost's API compliance standards and may cause unexpected cache behavior.",
    "fix_patch": "--- a/ghost/core/core/server/api/endpoints/comment-likes.js
